import React, { useEffect, useState, useMemo } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  Table,
  Tag,
  Button,
  Drawer,
  Descriptions,
  message,
  Tabs,
  Badge,
  Skeleton,
  Empty,
  Form,
  Select,
  Avatar,
  Alert,
} from "antd";
import { getOrders, updateAOrder } from "../features/auth/authSlice";
import { fetchDeliveryBoys } from "../features/delivery/deliveryBoySlice";
import {
  Eye,
  Clock,
  UserCheck,
  Rocket,
  CheckCircle,
  Package,
  Truck,
  ShieldCheck,
  Activity,
  User,
  Home,
  Save,
  ChevronRight,
  X,
} from "lucide-react";

const { TabPane } = Tabs;

// Status tag helper
const getStatusTag = (status) => {
  switch (status?.toLowerCase()) {
    case "pending":
      return (
        <Tag
          color="warning"
          className="rounded-full text-[10px] font-black uppercase tracking-widest"
        >
          Pending
        </Tag>
      );
    case "assigned":
      return (
        <Tag
          color="processing"
          className="rounded-full text-[10px] font-black uppercase tracking-widest"
        >
          Assigned
        </Tag>
      );
    case "active":
    case "shipped":
    case "processing":
      return (
        <Tag
          color="blue"
          className="rounded-full text-[10px] font-black uppercase tracking-widest"
        >
          In Transit
        </Tag>
      );
    case "delivered":
      return (
        <Tag
          color="success"
          className="rounded-full text-[10px] font-black uppercase tracking-widest"
        >
          Delivered
        </Tag>
      );
    default:
      return (
        <Tag className="rounded-full text-[10px] font-black uppercase tracking-widest">
          {status}
        </Tag>
      );
  }
};

const AdminOrderManagement = () => {
  const dispatch = useDispatch();
  const [form] = Form.useForm();
  const [isDrawerVisible, setIsDrawerVisible] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState(null);

  useEffect(() => {
    dispatch(getOrders());
    dispatch(fetchDeliveryBoys());
  }, [dispatch]);

  const {
    orders,
    isLoading,
    isError,
    message: orderMessage,
  } = useSelector((state) => state.auth);
  const { deliveryBoys, isLoading: deliveryLoading } = useSelector(
    (state) => state.deliveryBoy,
  );

  const filteredOrders = useMemo(() => {
    const pending = [];
    const assigned = [];
    const active = [];
    const delivered = [];
    const tot = orders.orders;
    (tot || []).forEach((order) => {
      switch (order.orderStatus?.toLowerCase()) {
        case "pending":
          pending.push(order);
          break;
        case "assigned":
          assigned.push(order);
          break;
        case "active":
        case "shipped":
        case "processing":
          active.push(order);
          break;
        case "delivered":
          delivered.push(order);
          break;
        default:
          break;
      }
    });
    return { pending, assigned, active, delivered };
  }, [orders]);

  const showDrawer = (order) => {
    setSelectedOrder(order);
    setIsDrawerVisible(true);
    form.resetFields();
  };

  const closeDrawer = () => {
    setIsDrawerVisible(false);
    setSelectedOrder(null);
  };

  const handleAssign = async (values) => {
    const { deliveryBoyId } = values;
    if (!deliveryBoyId) {
      message.error("Please select a delivery boy.");
      return;
    }
    const key = "assigning";
    message.loading({ content: "Assigning order...", key });
    try {
      await dispatch(
        updateAOrder({
          id: selectedOrder._id,
          deliveryBoyId: deliveryBoyId,
          status: "assigned",
        }),
      ).unwrap();
      message.success({ content: "Order assigned successfully!", key });
      closeDrawer();
      dispatch(getOrders());
    } catch (error) {
      message.error({ content: `Failed to assign: ${error.message}`, key });
    }
  };

  const columns = [
    {
      title: "ORDER",
      dataIndex: "_id",
      render: (id) => (
        <span className="font-mono text-[10px] font-black text-slate-400 bg-slate-50 px-2 py-1 rounded-md">
          #{id?.slice(-8).toUpperCase()}
        </span>
      ),
    },
    {
      title: "CUSTOMER",
      dataIndex: "user",
      render: (user) => (
        <div className="flex items-center gap-2">
          <Avatar
            size={28}
            src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.firstname}`}
            className="rounded-lg ring-1 ring-slate-100"
          />
          <span className="font-bold text-slate-900 text-xs">
            {user?.firstname || "N/A"} {user?.lastname || ""}
          </span>
        </div>
      ),
    },
    {
      title: "DATE",
      dataIndex: "createdAt",
      render: (date) => (
        <span className="text-[11px] text-slate-500 font-medium">
          {new Date(date).toLocaleDateString()}
        </span>
      ),
    },
    {
      title: "TOTAL",
      dataIndex: "totalPriceAfterDiscount",
      render: (price) => (
        <span className="font-black text-slate-900 text-xs">
          ${price?.toFixed(2)}
        </span>
      ),
    },
    {
      title: "STATUS",
      dataIndex: "orderStatus",
      render: getStatusTag,
    },
    {
      title: "ACTION",
      key: "action",
      render: (_, record) => (
        <Button
          type="text"
          icon={<Eye size={16} />}
          onClick={() => showDrawer(record)}
          className="text-[#257CB7] hover:text-blue-800 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2"
        >
          View
        </Button>
      ),
    },
  ];

  if (isLoading || deliveryLoading) {
    return (
      <div className="enterprise-card bg-white p-12 border-none shadow-2xl shadow-slate-200/40">
        <Skeleton active paragraph={{ rows: 8 }} />
      </div>
    );
  }

  if (isError) {
    return (
      <Alert
        message="Error"
        description={orderMessage}
        type="error"
        showIcon
        className="rounded-2xl"
      />
    );
  }

  const totalOrders =
    filteredOrders.pending.length +
    filteredOrders.assigned.length +
    filteredOrders.active.length +
    filteredOrders.delivered.length;

  // Status timeline for drawer
  const statusSteps = [
    { key: "pending", label: "Pending", icon: <Clock size={16} /> },
    { key: "assigned", label: "Assigned", icon: <UserCheck size={16} /> },
    { key: "active", label: "In Transit", icon: <Rocket size={16} /> },
    { key: "delivered", label: "Delivered", icon: <CheckCircle size={16} /> },
  ];

  const getStepStatus = (stepKey) => {
    const order = ["pending", "assigned", "active", "delivered"];
    const currentIndex = order.indexOf(
      selectedOrder?.orderStatus?.toLowerCase(),
    );
    const stepIndex = order.indexOf(stepKey);
    if (stepIndex <= currentIndex) return "completed";
    return "pending";
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Package size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              Order Management
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Package size={12} /> {totalOrders} Total Orders
            </span>
            <span className="flex items-center gap-2 text-[10px] font-black text-amber-600 bg-amber-50 border border-amber-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Clock size={12} /> {filteredOrders.pending.length} Pending
            </span>
            <span className="flex items-center gap-2 text-[10px] font-black text-emerald-600 bg-emerald-50 border border-emerald-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Activity size={12} /> System Active
            </span>
          </div>
        </div>
      </div>

      {/* Tabs Card */}
      <div className="enterprise-card bg-white p-6 border-none shadow-2xl shadow-slate-200/40">
        <Tabs defaultActiveKey="1" className="enterprise-tabs">
          <TabPane
            tab={
              <Badge count={filteredOrders.pending.length} offset={[10, -5]}>
                <span className="flex items-center gap-2 font-bold text-xs uppercase tracking-widest">
                  <Clock size={14} /> Pending
                </span>
              </Badge>
            }
            key="1"
          >
            <Table
              columns={columns}
              dataSource={filteredOrders.pending}
              rowKey="_id"
              pagination={{ pageSize: 10 }}
              locale={{
                emptyText: <Empty description="No Pending Orders" />,
              }}
              className="enterprise-table"
            />
          </TabPane>
          <TabPane
            tab={
              <Badge count={filteredOrders.assigned.length} offset={[10, -5]}>
                <span className="flex items-center gap-2 font-bold text-xs uppercase tracking-widest">
                  <UserCheck size={14} /> Assigned
                </span>
              </Badge>
            }
            key="2"
          >
            <Table
              columns={columns}
              dataSource={filteredOrders.assigned}
              rowKey="_id"
              pagination={{ pageSize: 10 }}
              locale={{
                emptyText: <Empty description="No Assigned Orders" />,
              }}
              className="enterprise-table"
            />
          </TabPane>
          <TabPane
            tab={
              <Badge count={filteredOrders.active.length} offset={[10, -5]}>
                <span className="flex items-center gap-2 font-bold text-xs uppercase tracking-widest">
                  <Rocket size={14} /> Active
                </span>
              </Badge>
            }
            key="3"
          >
            <Table
              columns={columns}
              dataSource={filteredOrders.active}
              rowKey="_id"
              pagination={{ pageSize: 10 }}
              locale={{
                emptyText: <Empty description="No Active Orders" />,
              }}
              className="enterprise-table"
            />
          </TabPane>
          <TabPane
            tab={
              <Badge count={filteredOrders.delivered.length} offset={[10, -5]}>
                <span className="flex items-center gap-2 font-bold text-xs uppercase tracking-widest">
                  <CheckCircle size={14} /> Delivered
                </span>
              </Badge>
            }
            key="4"
          >
            <Table
              columns={columns}
              dataSource={filteredOrders.delivered}
              rowKey="_id"
              pagination={{ pageSize: 10 }}
              locale={{
                emptyText: <Empty description="No Delivered Orders" />,
              }}
              className="enterprise-table"
            />
          </TabPane>
        </Tabs>
      </div>

      {/* Order Details Drawer */}
      <Drawer
        title={null}
        width={640}
        onClose={closeDrawer}
        open={isDrawerVisible}
        bodyStyle={{ padding: 0, background: "#f8fafc" }}
        headerStyle={{ display: "none" }}
      >
        {selectedOrder && (
          <div className="space-y-0">
            {/* Drawer Header */}
            <div className="bg-[#1e3a8a] p-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 opacity-10">
                <Package size={200} className="text-white" />
              </div>
              <div className="relative z-10">
                <div className="flex justify-between items-start">
                  <div>
                    <span className="text-[10px] font-black text-blue-300 uppercase tracking-widest mb-2 block">
                      Order Details
                    </span>
                    <h2 className="text-2xl font-black text-white tracking-tighter">
                      #{selectedOrder._id?.slice(-8).toUpperCase()}
                    </h2>
                  </div>
                  <button
                    onClick={closeDrawer}
                    className="p-2 text-white/50 hover:text-white transition-colors"
                  >
                    <X size={20} />
                  </button>
                </div>
                <div className="mt-4 flex gap-3">
                  {getStatusTag(selectedOrder.orderStatus)}
                  <span className="text-[10px] text-blue-200 font-bold">
                    {new Date(selectedOrder.createdAt).toLocaleDateString()}
                  </span>
                </div>
              </div>
            </div>

            {/* Progress Timeline */}
            <div className="p-8">
              <div className="flex justify-between items-center relative mb-10">
                <div className="absolute left-0 right-0 top-1/2 h-0.5 bg-slate-100" />
                {statusSteps.map((step, i) => {
                  const status = getStepStatus(step.key);
                  return (
                    <div
                      key={step.key}
                      className="relative z-10 flex flex-col items-center"
                    >
                      <div
                        className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                          status === "completed"
                            ? "bg-[#257CB7] text-white shadow-lg shadow-blue-500/20"
                            : "bg-slate-100 text-slate-300"
                        }`}
                      >
                        {step.icon}
                      </div>
                      <span
                        className={`text-[9px] font-black uppercase tracking-widest mt-2 ${
                          status === "completed"
                            ? "text-[#257CB7]"
                            : "text-slate-300"
                        }`}
                      >
                        {step.label}
                      </span>
                    </div>
                  );
                })}
              </div>

              {/* Customer & Shipping Info */}
              <div className="grid grid-cols-2 gap-6 mb-8">
                <div className="enterprise-card bg-white p-6 border-none shadow-md">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <User size={12} /> Customer
                  </h4>
                  <div className="space-y-3">
                    <p className="text-sm font-bold text-slate-900">
                      {selectedOrder?.first_name} {selectedOrder?.last_name}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {selectedOrder?.email}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {selectedOrder?.phone_number}
                    </p>
                  </div>
                </div>
                <div className="enterprise-card bg-white p-6 border-none shadow-md">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <Home size={12} /> Shipping
                  </h4>
                  <div className="space-y-3">
                    <p className="text-sm font-bold text-slate-900">
                      {selectedOrder?.address}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {selectedOrder?.city}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {selectedOrder?.country}
                    </p>
                  </div>
                </div>
              </div>

              {/* Items */}
              <div className="mb-8">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                  <Package size={12} /> Items Ordered
                </h4>
                <div className="space-y-3">
                  {selectedOrder.cart?.map((item) => (
                    <div
                      key={item._id}
                      className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100"
                    >
                      <div className="flex items-center gap-3">
                        <Avatar
                          shape="square"
                          size={48}
                          src={
                            item.product?.images?.[0]?.secure_url ||
                            item.product?.colors?.[0]?.images?.[0]?.secure_url ||
                            "https://res.cloudinary.com/dpkv77m87/image/upload/v1711200000/fallback_product_image.png"
                          }
                          className="rounded-xl"
                        />
                        <div>
                          <p className="font-bold text-slate-900 text-xs">
                            {item.product?.title}
                          </p>
                          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                            Qty: {item.quantity}
                          </p>
                        </div>
                      </div>
                      <span className="font-black text-slate-900 text-sm">
                        ${(item.price * item.quantity).toFixed(2)}
                      </span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Total */}
              <div className="flex justify-between items-center p-6 bg-slate-50 rounded-2xl border border-slate-100 mb-8">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Order Total
                </span>
                <span className="text-2xl font-black text-slate-900 tracking-tighter">
                  ${selectedOrder.totalPriceAfterDiscount?.toFixed(2)}
                </span>
              </div>

              {/* Assign Delivery Form */}
              {selectedOrder.orderStatus === "pending" && (
                <div className="enterprise-card bg-white p-8 border-none shadow-md">
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6 flex items-center gap-3">
                    <Truck size={18} className="text-[#257CB7]" /> Assign
                    Delivery Agent
                  </h4>
                  <Form form={form} layout="vertical" onFinish={handleAssign}>
                    <Form.Item
                      name="deliveryBoyId"
                      rules={[
                        {
                          required: true,
                          message: "Please select an agent",
                        },
                      ]}
                    >
                      <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2 mb-2">
                        <ChevronRight size={12} /> Select Agent
                      </label>
                      <Select
                        placeholder="Choose delivery agent"
                        className="w-full h-12"
                      >
                        {(deliveryBoys || []).map((boy) => (
                          <Select.Option key={boy._id} value={boy._id}>
                            {boy.firstname} {boy.lastname}
                          </Select.Option>
                        ))}
                      </Select>
                    </Form.Item>
                    <Form.Item>
                      <Button
                        type="primary"
                        htmlType="submit"
                        block
                        size="large"
                        icon={<Save size={16} />}
                        className="bg-[#257CB7] rounded-2xl h-14 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none flex items-center justify-center gap-3"
                      >
                        Assign Order
                      </Button>
                    </Form.Item>
                  </Form>
                </div>
              )}
            </div>
          </div>
        )}
      </Drawer>
    </div>
  );
};

export default AdminOrderManagement;
